// api-version is embedded in the resource declaration
resource vm 'Microsoft.Compute/virtualMachines@2023-09-01' = {
  name: 'myVM'
  location: location
  properties: {
    hardwareProfile: { vmSize: 'Standard_DS2_v2' }
    // ...
  }
}

// Each resource type pins its own api-version independently
resource sa 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystorageaccount'
  location: location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

// If your Bicep template deploys a resource whose provider is not yet registered,
// ARM registers it automatically before proceeding — no manual step needed.

// Example: deploying AKS for the first time in a subscription
// Microsoft.ContainerService is registered automatically by ARM

resource aks 'Microsoft.ContainerService/managedClusters@2024-01-01' = {
  name: 'myAKSCluster'
  location: location
  identity: { type: 'SystemAssigned' }
  properties: {
    kubernetesVersion: '1.29.0'
    dnsPrefix: 'myaks'
    agentPoolProfiles: [
      {
        name: 'nodepool1'
        count: 3
        vmSize: 'Standard_DS2_v2'
        mode: 'System'
      }
    ]
  }
}

// For subscription-level deployments bootstrapping a new environment,
// you can use a module to ensure providers are registered before dependent resources.

// providers-registration.bicep (targetScope = 'subscription')
targetScope = 'subscription'

param providers array = [
  'Microsoft.ContainerService'
  'Microsoft.ContainerRegistry'
  'Microsoft.OperationalInsights'
  'Microsoft.Insights'
]

@batchSize(1)
resource providerReg 'Microsoft.Resources/resourceProviders@2021-04-01' = [for ns in providers: {
  // Note: provider registration at subscription scope is handled implicitly
  // by ARM when resources are deployed; explicit registration modules are
  // rarely needed outside of automated subscription vending pipelines.
  name: ns
}]

import subprocess, json

def get_zone_support(namespace, resource_type, location_display_name):
    """Return the availability zones supported for a resource type in a location."""
    result = subprocess.run(
        ["az", "provider", "show", "--namespace", namespace,
         "--query", f"resourceTypes[?resourceType=='{resource_type}'].zoneMappings",
         "--output", "json"],
        capture_output=True, text=True, check=True
    )
    zone_mappings = json.loads(result.stdout)
    if not zone_mappings:
        return []
    for mapping in zone_mappings[0]:
        if mapping["location"].lower() == location_display_name.lower():
            return mapping.get("zones", [])
    return []

zones = get_zone_support("Microsoft.Compute", "virtualMachines", "East US")
print(f"VM availability zones in East US: {zones}")
# Example output: ['1', '2', '3']
